    public int deleteMatchingNode(String apname,int domainId,String prefix){
        BDBWorker worker=new BDBWorker(apname);
        List<Integer> nodes=new ArrayList<>();
        try{
            SDBQuery q=new SDBQueryFull(worker);
            q.go(domainId);
            SDBNode node;
            while((node=q.next())!=null){
                String value=node.getValue();
                boolean prefixMatch=prefix==null || value.startsWith(prefix);
                if(value!=null && prefixMatch){
                    nodes.add(node.getId());
                }
            }
        }
        finally {
            worker.commit();
        }

        EnvironmentConfig envConfig = new EnvironmentConfig();
        File dir=new File("cust/data/"+apname);
        //envConfig.setTransactional(false);
        envConfig.setTransactional(true);
        envConfig.setTxnTimeout(Const.TXN_LOCK_TIMEOUT_SEC, TimeUnit.SECONDS);

        EnvironmentMutableConfig emc=new EnvironmentMutableConfig();
        //emc.setCachePercent(1);
        envConfig.setSharedCache(true);
        Environment env = new Environment(dir, envConfig);
        env.setMutableConfig(emc);

        DatabaseConfig valueDBConfig = new DatabaseConfig();
        valueDBConfig.setDeferredWrite(false);
        valueDBConfig.setTransactional(true);
        valueDBConfig.setKeyPrefixing(true);//this is marked because there's a strange bug that one db's environment failure affects other db's initialization, we will see if this makes it affect other dbs
        Database valueDB = null;//txn

        int count=0;
        try {
            valueDB = env.openDatabase(null,"v",valueDBConfig);//no transaction handle provided, auto-commit

            for(int nodeId:nodes){
                DatabaseEntry theKey = new DatabaseEntry();
                ValueKey vkey=new ValueKey(domainId,nodeId);
                BDBMgr.getValueDBKeyTupleBinding().objectToEntry(vkey,theKey);
                try {
                    valueDB.delete(null,theKey);
                    count++;
                }
                catch (Exception e){
                    ExceptionManager.getInstance().processException(e);
                }
            }
        }
        catch (Exception e){
            ExceptionManager.getInstance().processException(e);
        }
        finally {
            valueDB.close();
            env.close();
        }

        return count;

    }
    public String getValue(String apname,int domainId,int nodeId){
        BDBWorker worker=new BDBWorker(apname);
        try{
            SDBNode node=worker.getNode(domainId,nodeId);
            if(node==null) return "null";
            return node.getValue();
        }
        finally {
            worker.commit();
        }
    }

